import org.junit.jupiter.api.Test;

class JoinQueryEvaluationStepTest {

	@Test
	void honorsHashJoinHint() {
		EvaluationStrategy strategy = strategyWithNoOpPrecompile();
		Join join = new Join(pattern("s", "urn:test:left", "join"), pattern("o", "urn:test:right", "join"));
		join.setAlgorithm(HashJoinIteration.class.getSimpleName());

		new JoinQueryEvaluationStep(strategy, join, new QueryEvaluationContext.Minimal(null));

		assertEquals(HashJoinIteration.class.getSimpleName(), join.getAlgorithmName());
	}

	@Test
	void honorsMergeJoinHintWhenComparatorAndOrderAvailable() {
		EvaluationStrategy strategy = strategyWithNoOpPrecompile();
		StatementPattern left = pattern("join", "urn:test:left", "a");
		StatementPattern right = pattern("join", "urn:test:right", "b");
		Join join = new Join(left, right);
		join.setAlgorithm(InnerMergeJoinIterator.class.getSimpleName());
		join.setOrder(new Var("join"));

		new JoinQueryEvaluationStep(strategy, join,
				new QueryEvaluationContext.Minimal(null, Comparator.comparing(Value::stringValue)));

		assertEquals(InnerMergeJoinIterator.class.getSimpleName(), join.getAlgorithmName());
	}

	private static EvaluationStrategy strategyWithNoOpPrecompile() {
		EvaluationStrategy strategy = mock(EvaluationStrategy.class);
		when(strategy.precompile(any(TupleExpr.class), any(QueryEvaluationContext.class)))
				.thenReturn(QueryEvaluationStep.empty());
		return strategy;
	}

	private static StatementPattern pattern(String subjectName, String predicateIri, String objectName) {
		return new StatementPattern(
				new Var(subjectName),
				new Var("p", SimpleValueFactory.getInstance().createIRI(predicateIri)),
				new Var(objectName));
	}
}
